const month = new Date().getMonth() + 1;
const week = Math.ceil(new Date().getDate() / 7);
const emails = [
  { subject: 'Spring is coming — time to prep your Madison yard!', body: 'Hi {name},

Spring is just around the corner! TotalGuard's spring cleanup service gets your yard ready for the season: debris removal, bed prep, and your first mow.

Book early — spots fill fast! tgyardcare.com or (608) 535-6057' },
  { subject: 'Lock in your weekly mowing rate before the rush', body: 'Hi {name},

Every spring our mowing schedule fills up fast. Lock in your rate now and get the same crew every week, guaranteed.

Book your weekly mowing at tgyardcare.com' },
  { subject: 'Complete spring package — cleanup + first mow + fertilization', body: 'Hi {name},

Our complete spring package includes: full yard cleanup, first mow of the season, and a fertilization treatment. One booking, handled.

Get your spring package at tgyardcare.com' }
];
const emailIdx = Math.min(week - 1, emails.length - 1);
const template = emails[emailIdx];
return $input.all().map(i => ({ json: { ...i.json, subject: template.subject, body: template.body.replace('{name}', i.json.first_name || 'there'), weekNum: emailIdx + 1 } }));
